 81→            swipeToRefreshHelper = WPSwipeToRefreshHelper.buildSwipeToRefreshHelper(swipeRefreshLayout) {
 82→                viewModel.onPullToRefresh()
 83→            }
 84→
 85→            (nonNullActivity.application as WordPress).component().inject(this@HistoryListFragment)
 86→
 87→            viewModel = ViewModelProvider(this@HistoryListFragment, viewModelFactory)[HistoryViewModel::class.java]
 88→            val site = requireNotNull(arguments?.getSerializableCompat<SiteModel>(KEY_SITE))
