148→                        actionableEmptyView.subtitle.setText(R.string.error_generic_network)
149→                        actionableEmptyView.subtitle.visibility = View.VISIBLE
150→                        actionableEmptyView.button.visibility = View.VISIBLE
151→                    }
152→                }
153→            }
154→        })
155→
156→        viewModel.showDialog.observe(viewLifecycleOwner, Observer { showDialogItem ->
157→            if (showDialogItem != null && showDialogItem.historyListItem is Revision) {
158→                (activity as HistoryItemClickInterface).onHistoryItemClicked(
159→                    showDialogItem.historyListItem,
160→                    showDialogItem.revisionsList
161→                )
162→            }
163→        })
164→
165→        viewModel.post.observe(viewLifecycleOwner, Observer { post ->
166→            actionableEmptyView.subtitle.text = if (post?.isPage == true) {
167→                getString(R.string.history_empty_subtitle_page)
168→            } else {
169→                getString(R.string.history_empty_subtitle_post)
170→            }
171→        })
172→    }
173→}
